def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    val = ((ratio - a) ** 6) / (a * b * 0.85 + 1.2)
                    priority += val * np.sin(ratio * b / (a + 0.8)) * np.exp(-0.1 * (i % (b + 1)))
            priority += (np.exp(ratio - 7) * np.cos(ratio * 1.2)) ** 1.7
            for c in range(1, 5):
                priority += np.tanh(ratio * c * i / (c + 3)) * (ratio - 6) ** 2 / (c + 1)
        elif 4 < ratio <= 7:
            for d in range(2, int(np.ceil(ratio)) + 4):
                for e in range(1, d + 3):
                    term = ((ratio - d) ** 4) * np.cos(ratio * d) / (e + 0.8)
                    priority += np.tanh(term) * 1.4
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4) * 3
            for f in range(1, 7):
                priority += np.sin(ratio * f * i) * ((ratio - 4) ** f) / (f + 0.5)
        elif 2 <= ratio <= 4:
            s1 = 0
            s2 = 0
            for g in range(1, 15):
                s1 += ((ratio - 2) ** g) / (g * 2.0) * np.sin(g * ratio * 1.1)
                s2 += ((4 - ratio) ** g) / (g + 1) * np.cos(g * ratio * 0.9)
            priority = (s1 * np.cos(8 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 2
            priority += s2 * 0.7
            if i % 2 == 0:
                priority += np.sin(ratio * i * 1.3) * 1.1
            else:
                priority -= np.cos(ratio * i * 1.3) * 1.1
        elif 0.7 <= ratio < 2:
            s3 = 0
            for h in range(1, 12):
                s3 += ((2 - ratio) ** h) / (h ** 2 + 1) * np.cos(h * ratio * 1.5)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5.5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s3 + penalty + np.exp(-1.2 / (ratio + 0.07))
            for j in range(1, 6):
                priority += np.sin(j * ratio * i * 0.9) * ((ratio - 0.7) ** j) / (j + 0.3)
            if i % 5 == 0:
                priority *= np.log1p(bin_cap + 5)
        elif 0.25 <= ratio < 0.7:
            s4 = 0
            for k in range(1, 18):
                s4 += ((0.7 - ratio) ** k) / (k * 3.5)
            priority = s4
            if (i + int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.6
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for l in range(1, 8):
                priority += ((0.7 - ratio) ** l) * np.sin(l * item * 1.3) * 0.9
        elif 0.05 <= ratio < 0.25:
            s5 = 0
            for m in range(1, 15):
                s5 += ((0.25 - ratio) ** m) / (m * 4) * np.cos(m * ratio * 2.5)
            priority = s5 + 1.5 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 0:
                priority *= 3
            else:
                priority /= 3.5
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.5) * 4.2
            for n in range(1, 9):
                priority += ((0.25 - ratio) ** n) / (n * 7) * np.cos(item * n * 1.3)
        else:
            s6 = 0
            for o in range(1, 12):
                s6 += ((0.05 - ratio) ** o) / (o * 6) * np.sin(o * item * 1.1)
            priority = s6 + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 3) * 5
            for p in range(1, 10):
                priority += ((0.05 - ratio) ** p) / (p * 8) * np.cos(item * p * 0.9)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 6.5
            priority += np.sin(ratio * i * 2) * 0.8
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5
            priority -= np.cos(ratio * (i + 1) * 1.5) * 0.7
        for q in range(1, 5):
            if (i + q) % 4 == 0:
                priority += np.sin(ratio * (i + q) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + q) * 1.4) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.5) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.5) * 0.7
        priorities[i] = priority
    return priorities
